239→		City:   "Testville",
240→		State:  "TX",
241→		NCES:   []byte(`{"control":1}`),
242→	}
243→
244→	if err := UpsertInstitution(ctx, pool, inst); err != nil {
245→		t.Fatalf("first upsert: %v", err)
246→	}
247→
248→	// Verify row exists.
