270→
271→	err = pool.QueryRow(ctx,
272→		"SELECT version FROM search_base.institution WHERE unit_id = $1",
273→		testUnitID,
274→	).Scan(&version)
275→	if err != nil {
276→		t.Fatalf("QueryRow after re-upsert: %v", err)
