package deadlines

import (
	"context"
	"encoding/json"
	"fmt"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
)

const (
	themeAdmissions  = "ADMISSIONS"
	datakeyDeadlines = "deadlines"
)

// StoreScrapedPage inserts a row into search_base.scraped_page and returns the
// generated id.
func StoreScrapedPage(ctx context.Context, pool *pgxpool.Pool, p *ScrapedPageParams) (int64, error) {
	const sql = `
INSERT INTO search_base.scraped_page (
    unit_id, page_type, url, content_text, content_html,
    api_response, http_status, content_hash
) VALUES ($1, $2, $3, $4, $5, $6, $7, $8)
RETURNING id`

	var id int64
	err := pool.QueryRow(ctx, sql,
		p.UnitID, p.PageType, p.URL, p.ContentText, p.ContentHTML,
		p.APIResponse, p.HTTPStatus, p.ContentHash,
	).Scan(&id)
	if err != nil {
		return 0, fmt.Errorf("deadlines: store scraped page %s/%s: %w", p.UnitID, p.PageType, err)
	}
	return id, nil
}

// UpsertDeadlines marshals data as JSON and upserts it into the annual_dataset
// table with theme=ADMISSIONS and datakey=deadlines.
func UpsertDeadlines(ctx context.Context, pool *pgxpool.Pool, unitID string, year int, data DeadlineData) error {
	raw, err := json.Marshal(data)
	if err != nil {
		return fmt.Errorf("deadlines: marshal data for %s/%d: %w", unitID, year, err)
	}
	ads := &dbutil.AnnualDataset{
		UnitID:  unitID,
		Year:    year,
		Theme:   themeAdmissions,
		Datakey: datakeyDeadlines,
		Data:    raw,
	}
	if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
		return fmt.Errorf("deadlines: upsert deadlines %s/%d: %w", unitID, year, err)
	}
	return nil
}

// LoadExistingDeadlines queries the annual_dataset table for existing deadline
// data. Returns a zero-value DeadlineData and nil error if no row is found.
func LoadExistingDeadlines(ctx context.Context, pool *pgxpool.Pool, unitID string, year int) (DeadlineData, error) {
	const sql = `
SELECT data FROM search_base.annual_dataset
WHERE unit_id = $1 AND year = $2 AND theme = $3 AND datakey = $4`

	var raw []byte
	err := pool.QueryRow(ctx, sql, unitID, year, themeAdmissions, datakeyDeadlines).Scan(&raw)
	if err != nil {
		// pgx returns ErrNoRows when no row is found
		if err.Error() == "no rows in result set" {
			return DeadlineData{}, nil
		}
		return DeadlineData{}, fmt.Errorf("deadlines: load existing %s/%d: %w", unitID, year, err)
	}

	var data DeadlineData
	if err := json.Unmarshal(raw, &data); err != nil {
		return DeadlineData{}, fmt.Errorf("deadlines: unmarshal existing %s/%d: %w", unitID, year, err)
	}
	return data, nil
}

