package deadlines

import (
	"encoding/json"
	"testing"
)

func TestDeadlineDataMarshalRoundTrip(t *testing.T) {
	original := DeadlineData{
		Plans: map[string]DeadlinePlan{
			PlanEarlyDecision1: {
				Deadline:     "2026-11-01",
				Notification: "2026-12-15",
				DepositDue:   "2027-01-15",
				Binding:      true,
				SourceURL:    "https://example.edu/admissions",
				Confidence:   "high",
			},
			PlanRolling: {
				Opens:             "2026-08-01",
				Closes:            "2027-06-01",
				NotificationWeeks: 4,
				Binding:           false,
				SourceURL:         "https://example.edu/admissions",
				Confidence:        "high",
			},
		},
		FeeUSD:              75,
		FeeWaiver:           true,
		HasEarlyDecision:    true,
		HasEarlyAction:      false,
		HasRollingAdmissions: false,
		SourceURLs:          []string{"https://example.edu/admissions"},
		ExtractedAt:         "2026-08-15T14:30:00Z",
		BigfutureID:         "1251",
		BigfutureAgrees:     true,
	}

	raw, err := json.Marshal(original)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var decoded DeadlineData
	if err := json.Unmarshal(raw, &decoded); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	// Verify plan count
	if len(decoded.Plans) != 2 {
		t.Errorf("expected 2 plans, got %d", len(decoded.Plans))
	}

	// Verify ED1 plan
	ed1, ok := decoded.Plans[PlanEarlyDecision1]
	if !ok {
		t.Fatal("missing early_decision_1 plan")
	}
	if ed1.Deadline != "2026-11-01" {
		t.Errorf("ED1 deadline = %q, want %q", ed1.Deadline, "2026-11-01")
	}
	if !ed1.Binding {
		t.Error("ED1 should be binding")
	}

	// Verify rolling plan
	rolling, ok := decoded.Plans[PlanRolling]
	if !ok {
		t.Fatal("missing rolling plan")
	}
	if rolling.NotificationWeeks != 4 {
		t.Errorf("rolling notification_weeks = %d, want 4", rolling.NotificationWeeks)
	}

	// Verify top-level fields
	if decoded.FeeUSD != 75 {
		t.Errorf("fee_usd = %d, want 75", decoded.FeeUSD)
	}
	if !decoded.FeeWaiver {
		t.Error("fee_waiver should be true")
	}
	if decoded.BigfutureID != "1251" {
		t.Errorf("bigfuture_id = %q, want %q", decoded.BigfutureID, "1251")
	}
}

func TestDeadlinePlanOmitEmpty(t *testing.T) {
	// A plan with only deadline fields set should omit rolling fields
	plan := DeadlinePlan{
		Deadline:   "2026-11-01",
		Confidence: "high",
	}

	raw, err := json.Marshal(plan)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var m map[string]any
	if err := json.Unmarshal(raw, &m); err != nil {
		t.Fatalf("unmarshal to map: %v", err)
	}

	// These fields should be present
	if _, ok := m["deadline"]; !ok {
		t.Error("expected deadline field in JSON")
	}
	if _, ok := m["confidence"]; !ok {
		t.Error("expected confidence field in JSON")
	}

	// These zero-value fields should be omitted
	for _, key := range []string{"notification", "deposit_due", "opens", "closes", "source_url"} {
		if _, ok := m[key]; ok {
			t.Errorf("expected %q to be omitted from JSON", key)
		}
	}
	if _, ok := m["binding"]; ok {
		t.Error("expected binding (false) to be omitted from JSON")
	}
	if _, ok := m["notification_weeks"]; ok {
		t.Error("expected notification_weeks (0) to be omitted from JSON")
	}
}

func TestDeadlineDataWithAllPlans(t *testing.T) {
	data := DeadlineData{
		Plans: make(map[string]DeadlinePlan),
	}

	allKeys := AllPlanKeys()
	for _, key := range allKeys {
		data.Plans[key] = DeadlinePlan{Confidence: "medium"}
	}

	raw, err := json.Marshal(data)
	if err != nil {
		t.Fatalf("marshal: %v", err)
	}

	var decoded DeadlineData
	if err := json.Unmarshal(raw, &decoded); err != nil {
		t.Fatalf("unmarshal: %v", err)
	}

	if len(decoded.Plans) != len(allKeys) {
		t.Errorf("expected %d plans, got %d", len(allKeys), len(decoded.Plans))
	}

	for _, key := range allKeys {
		plan, ok := decoded.Plans[key]
		if !ok {
			t.Errorf("missing plan key %q after round-trip", key)
			continue
		}
		if plan.Confidence != "medium" {
			t.Errorf("plan %q confidence = %q, want %q", key, plan.Confidence, "medium")
		}
	}
}

func TestScrapedPageParams(t *testing.T) {
	html := "<html>test</html>"
	status := int16(200)
	hash := "abc123"

	p := ScrapedPageParams{
		UnitID:      "100654",
		PageType:    "bigfuture",
		URL:         "https://example.com/page",
		ContentText: "test content",
		ContentHTML: &html,
		APIResponse: []byte(`{"key":"value"}`),
		HTTPStatus:  &status,
		ContentHash: &hash,
	}

	if p.UnitID != "100654" {
		t.Errorf("UnitID = %q, want %q", p.UnitID, "100654")
	}
	if p.PageType != "bigfuture" {
		t.Errorf("PageType = %q, want %q", p.PageType, "bigfuture")
	}
	if *p.ContentHTML != html {
		t.Errorf("ContentHTML = %q, want %q", *p.ContentHTML, html)
	}
	if *p.HTTPStatus != 200 {
		t.Errorf("HTTPStatus = %d, want 200", *p.HTTPStatus)
	}
	if *p.ContentHash != hash {
		t.Errorf("ContentHash = %q, want %q", *p.ContentHash, hash)
	}

	// Verify nil optional fields work
	pMinimal := ScrapedPageParams{
		UnitID:      "100654",
		PageType:    "bigfuture",
		URL:         "https://example.com/page",
		ContentText: "test content",
	}
	if pMinimal.ContentHTML != nil {
		t.Error("expected ContentHTML to be nil")
	}
	if pMinimal.HTTPStatus != nil {
		t.Error("expected HTTPStatus to be nil")
	}
	if pMinimal.ContentHash != nil {
		t.Error("expected ContentHash to be nil")
	}
